<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Conway's Game of Life</title>
  <style>
    :root {
      --bg-color: #1a1a2e;
      --grid-bg: #16213e;
      --cell-alive: #0f3460;
      --cell-border: #533483;
      --text-color: #e94560;
      --btn-bg: #16213e;
      --btn-hover: #0f3460;
      --btn-text: #e94560;
    }

    body {
      margin: 0;
      padding: 0;
      background-color: var(--bg-color);
      color: white;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-height: 100vh;
    }

    h1 {
      margin-top: 20px;
      color: var(--text-color);
      text-align: center;
    }

    .controls {
      display: flex;
      gap: 15px;
      margin: 20px 0;
      flex-wrap: wrap;
      justify-content: center;
    }

    button {
      background-color: var(--btn-bg);
      color: var(--btn-text);
      border: 2px solid var(--text-color);
      padding: 10px 20px;
      font-size: 16px;
      cursor: pointer;
      border-radius: 8px;
      transition: all 0.3s ease;
    }

    button:hover {
      background-color: var(--btn-hover);
      transform: translateY(-2px);
    }

    button:active {
      transform: translateY(0);
    }

    #life-container {
      position: relative;
      box-shadow: 0 0 20px rgba(233, 69, 96, 0.5);
      border-radius: 8px;
      overflow: hidden;
    }

    canvas#life {
      background-color: var(--grid-bg);
      cursor: crosshair;
      display: block;
    }

    .stats {
      margin-top: 10px;
      font-size: 14px;
      color: #aaa;
    }
  </style>
</head>
<body>
  <h1>Conway's Game of Life</h1>

  <div class="controls">
    <button id="step">Step</button>
    <button id="play">Play/Pause</button>
    <button id="random">Randomize</button>
    <button id="clear">Clear</button>
  </div>

  <div id="life-container">
    <canvas id="life"></canvas>
  </div>

  <div class="stats">
    Generation: <span id="generation">0</span> | 
    Population: <span id="population">0</span>
  </div>

  <script>
    // Game of Life Implementation
    class GameOfLife {
      constructor(canvasId, w = 40, h = 40) {
        this.canvas = document.getElementById(canvasId);
        this.ctx = this.canvas.getContext('2d');
        this.w = w;
        this.h = h;

        // Set canvas size to match grid
        const cellSize = 10; // pixels per cell
        this.canvas.width = w * cellSize;
        this.canvas.height = h * cellSize;

        // CSS size (at least 400x400)
        this.canvas.style.width = '400px';
        this.canvas.style.height = '400px';

        // Initialize grid
        this.grid = [];
        this.nextGrid = [];
        for (let y = 0; y < h; y++) {
          const row = new Array(w).fill(0);
          const nextRow = new Array(w).fill(0);
          this.grid.push(row);
          this.nextGrid.push(nextRow);
        }

        this.generation = 0;
        this.isPlaying = false;
        this.animationId = null;

        // Mouse interaction
        this.isDrawing = false;
        this.drawMode = 1; // 1 for drawing alive, 0 for erasing

        // Bind events
        this.canvas.addEventListener('mousedown', (e) => {
          this.isDrawing = true;
          const { x, y } = this.getGridPos(e);
          if (x >= 0 && x < w && y >= 0 && y < h) {
            this.drawMode = this.grid[y][x] ? 0 : 1;
            this.set(x, y, this.drawMode);
          }
        });

        this.canvas.addEventListener('mousemove', (e) => {
          if (this.isDrawing) {
            const { x, y } = this.getGridPos(e);
            if (x >= 0 && x < w && y >= 0 && y < h) {
              this.set(x, y, this.drawMode);
            }
          }
        });

        window.addEventListener('mouseup', () => {
          this.isDrawing = false;
        });

        // Initial render
        this.render();
      }

      getGridPos(e) {
        const rect = this.canvas.getBoundingClientRect();
        const scaleX = this.w / rect.width;
        const scaleY = this.h / rect.height;

        return {
          x: Math.floor((e.clientX - rect.left) * scaleX),
          y: Math.floor((e.clientY - rect.top) * scaleY)
        };
      }

      get(x, y) {
        if (x < 0 || x >= this.w || y < 0 || y >= this.h) return 0;
        return this.grid[y][x];
      }

      set(x, y, value) {
        if (x >= 0 && x < this.w && y >= 0 && y < this.h) {
          this.grid[y][x] = value ? 1 : 0;
        }
      }

      countNeighbors(x, y) {
        let count = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            count += this.get(x + dx, y + dy);
          }
        }
        return count;
      }

      step() {
        // Compute next generation using B3/S23 rules
        for (let y = 0; y < this.h; y++) {
          for (let x = 0; x < this.w; x++) {
            const neighbors = this.countNeighbors(x, y);
            const current = this.grid[y][x];

            if (current === 1) {
              // Live cell: survives with 2 or 3 neighbors
              this.nextGrid[y][x] = (neighbors === 2 || neighbors === 3) ? 1 : 0;
            } else {
              // Dead cell: becomes alive with exactly 3 neighbors
              this.nextGrid[y][x] = (neighbors === 3) ? 1 : 0;
            }
          }
        }

        // Swap grids
        [this.grid, this.nextGrid] = [this.nextGrid, this.grid];

        this.generation++;
        this.render();
      }

      render() {
        const cellSize = this.canvas.width / this.w;

        // Clear canvas
        this.ctx.fillStyle = '#16213e'; // grid background color
        this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

        // Draw alive cells
        this.ctx.fillStyle = '#533483';
        let population = 0;

        for (let y = 0; y < this.h; y++) {
          for (let x = 0; x < this.w; x++) {
            if (this.grid[y][x] === 1) {
              population++;
              // Draw cell with slight padding
              const px = Math.floor(x * cellSize);
              const py = Math.floor(y * cellSize);
              const size = Math.ceil(cellSize);

              this.ctx.fillRect(px, py, size, size);

              // Add a subtle border effect for visibility
              if (x < this.w - 1) {
                this.ctx.fillStyle = '#e94560';
                this.ctx.fillRect(px + cellSize - 2, py, 2, size);
                this.ctx.fillStyle = '#533483';
              }
            }
          }
        }

        // Update stats
        document.getElementById('generation').textContent = this.generation;
        document.getElementById('population').textContent = population;
      }

      clear() {
        for (let y = 0; y < this.h; y++) {
          for (let x = 0; x < this.w; x++) {
            this.grid[y][x] = 0;
          }
        }
        this.generation = 0;
        this.render();
      }

      random() {
        for (let y = 0; y < this.h; y++) {
          for (let x = 0; x < this.w; x++) {
            this.grid[y][x] = Math.random() > 0.8 ? 1 : 0;
          }
        }
        this.generation = 0;
        this.render();
      }

      play() {
        if (!this.isPlaying) {
          this.isPlaying = true;
          const loop = () => {
            if (this.isPlaying) {
              this.step();
              this.animationId = requestAnimationFrame(loop);
            }
          };
          loop();
        }
      }

      pause() {
        this.isPlaying = false;
        if (this.animationId) {
          cancelAnimationFrame(this.animationId);
          this.animationId = null;
        }
      }

      togglePlay() {
        if (this.isPlaying) {
          this.pause();
        } else {
          this.play();
        }
      }
    }

    // Initialize the game
    const game = new GameOfLife('life', 40, 40);

    // Expose API to window as required
    window.life = {
      w: game.w,
      h: game.h,
      get(x, y) { return game.get(x, y); },
      set(x, y, v) { game.set(x, y, v); },
      step() { 
        game.pause(); // Stop auto-play when manually stepping
        game.step();
      },
      clear() {
        game.pause();
        game.clear();
      }
    };

    // Button event listeners
    document.getElementById('step').addEventListener('click', () => {
      game.pause();
      game.step();
    });

    document.getElementById('play').addEventListener('click', () => {
      game.togglePlay();
    });

    document.getElementById('random').addEventListener('click', () => {
      game.pause();
      game.random();
    });

    document.getElementById('clear').addEventListener('click', () => {
      game.clear();
    });

    // Add some initial patterns for fun
    window.onload = () => {
      // Glider pattern
      const startX = 1;
      const startY = 1;
      game.set(startX + 1, startY, 1);
      game.set(startX + 2, startY + 1, 1);
      game.set(startX, startY + 2, 1);
      game.set(startX + 1, startY + 2, 1);
      game.set(startX + 2, startY + 2, 1);

      // Blinker pattern
      const blinkerX = 10;
      const blinkerY = 5;
      game.set(blinkerX, blinkerY, 1);
      game.set(blinkerX + 1, blinkerY, 1);
      game.set(blinkerX + 2, blinkerY, 1);

      // Block pattern (stable)
      const blockX = 5;
      const blockY = 10;
      game.set(blockX, blockY, 1);
      game.set(blockX + 1, blockY, 1);
      game.set(blockX, blockY + 1, 1);
      game.set(blockX + 1, blockY + 1, 1);

      // Random cells
      game.random();
    };
  </script>
</body>
</html>
